import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) throws IOException {
        String userInput = "../../../../../etc/passwd";

        // Define the base directory to restrict file access within
        String baseDirectory = "/path/to/some/directory/";

        // Resolve the user input against the base directory to prevent path traversal
        Path resolvedPath = Paths.get(baseDirectory, userInput).normalize();

        if (!resolvedPath.startsWith(baseDirectory)) {
            System.out.println("Invalid file path specified");
            return;
        }

        File file = resolvedPath.toFile();

        if (file.exists()) {
            byte[] fileContent = Files.readAllBytes(file.toPath());
            System.out.println(new String(fileContent));
        } else {
            System.out.println("File not found");
        }
    }
}

